// friday13.cs — Friday the 13th experiments with the proleptic Gregorian calendar

// Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateOnly(1, 1, 13); // start on the 13th of January, year 1
while (date.DayOfWeek != DayOfWeek.Friday)
{
    date = date.AddMonths(1);
}
Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var start = new DateOnly(1, 1, 13);
var end = new DateOnly(401, 1, 1);
var current = start;
while (current < end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        count++;
    current = current.AddMonths(1);
}
Console.WriteLine($"Friday the 13ths in a 400-year cycle (0001–0400): {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// Bonus: distribution by month
var byMonth = new int[12];
current = start;
while (current < end)
{
    if (current.DayOfWeek == DayOfWeek.Friday)
        byMonth[current.Month - 1]++;
    current = current.AddMonths(1);
}
Console.WriteLine("\nDistribution by month:");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateOnly(2000, m + 1, 1):MMMM,-10} {byMonth[m]}");

